table.ejecuta:

ob_start();
if( 'fiscal' == '1' ) {
    try 
    {
		$calculo = new EmiteFiscal();
		$calculo->setHomo( $_SESSION['properties']['wsafiphomo'] );
		$calculo->setPrinter('printer');
		$calculo->imprimir('id_regmovim');
		ob_get_clean();
    } catch(Exception $e) {
		loger($e, 'webservice.log');
		_rollback_transaction('',false);

		ob_get_clean();
		header('HTTP/1.1 500 Bad Request', $e->getMessage());
		die($e->getMessage());
    }
} else { }
